    cast(model?: Model<any, THelpers> | null, obj?: any): any;

    
    catch: Promise<ResultType>['catch'];

    
    finally: Promise<ResultType>['finally'];

    
    [Symbol.toStringTag]: string;

    
    circle(path: string, area: any): this;
    circle(area: any): this;

    
